import requests
from datetime import datetime, timedelta


class Tools:
    @staticmethod
    def run(
        query: str = None,
        category: str = None,
        days_back: int = 7,
        max_results: int = 20,
    ) -> dict:
        """
        Search recent arXiv papers (no API key needed).
        query: keywords in title/abstract
        category: e.g. cs.LG, stat.ML, physics:hep-th
        days_back: how far back to search (default 7 days)
        """
        base_url = "http://export.arxiv.org/api/query"

        date_from = (datetime.utcnow() - timedelta(days=days_back)).strftime("%Y%m%d")
        date_to = datetime.utcnow().strftime("%Y%m%d")

        search_query = f"submittedDate:[{date_from} TO {date_to}]"
        if query:
            search_query += f' AND all:"{query}"'
        if category:
            search_query += f' AND cat:"{category}"'

        params = {
            "search_query": search_query,
            "start": 0,
            "max_results": max_results,
            "sortBy": "submittedDate",
            "sortOrder": "descending",
        }

        try:
            r = requests.get(base_url, params=params, timeout=15)
            r.raise_for_status()
            # arXiv returns Atom XML — parse simply
            from xml.etree import ElementTree as ET

            root = ET.fromstring(r.content)
            ns = {"atom": "http://www.w3.org/2005/Atom"}
            entries = []

            for entry in root.findall("atom:entry", ns):
                paper = {
                    "title": (
                        entry.find("atom:title", ns).text.strip()
                        if entry.find("atom:title", ns) is not None
                        else ""
                    ),
                    "id": (
                        entry.find("atom:id", ns).text
                        if entry.find("atom:id", ns) is not None
                        else ""
                    ),
                    "summary": (
                        entry.find("atom:summary", ns).text.strip()
                        if entry.find("atom:summary", ns) is not None
                        else ""
                    ),
                    "published": (
                        entry.find("atom:published", ns).text
                        if entry.find("atom:published", ns) is not None
                        else ""
                    ),
                    "authors": [
                        a.text for a in entry.findall("atom:author/atom:name", ns)
                    ],
                    "pdf": next(
                        (
                            link.get("href")
                            for link in entry.findall("atom:link", ns)
                            if link.get("title") == "pdf"
                        ),
                        None,
                    ),
                }
                entries.append(paper)

            return {"results": entries, "total_found": len(entries)}
        except Exception as e:
            return {"error": str(e)}
